using System.Collections.Concurrent;

namespace sv_19a9578ca5ea4e399ca3b78439ac7384.Services;

public class PersonalInfo
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
}

public class ExperienceEntry
{
    public string Company { get; set; } = "";
    public string Role { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceEntry
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

public class WizardData
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public List<ExperienceEntry> Experience { get; set; } = [new()];
    public List<ReferenceEntry> References { get; set; } = [new()];
    public HashSet<int> CompletedSteps { get; set; } = [];
    public int CurrentStep { get; set; } = 1;
    public DateTime LastAccessed { get; set; } = DateTime.UtcNow;
}

/// <summary>
/// Singleton store keyed by a per-browser cookie. Safe for concurrent
/// applicants because each gets their own dictionary entry.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new WizardData());
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }

    /// <summary>
    /// Call periodically or on app startup to remove stale sessions.
    /// </summary>
    public void PurgeStale(TimeSpan maxAge)
    {
        var cutoff = DateTime.UtcNow - maxAge;
        foreach (var key in _store.Keys)
        {
            if (_store.TryGetValue(key, out var data) && data.LastAccessed < cutoff)
            {
                _store.TryRemove(key, out _);
            }
        }
    }
}

namespace sv_19a9578ca5ea4e399ca3b78439ac7384.Services;

/// <summary>
/// Reads or creates the wizard session cookie so both static SSR and
/// interactive components identify the same applicant session.
/// </summary>
public static class WizardSessionHelper
{
    public const string CookieName = "WizardSessionId";

    public static string GetOrCreateSessionId(HttpContext httpContext)
    {
        if (httpContext.Request.Cookies.TryGetValue(CookieName, out var id) &&
            !string.IsNullOrEmpty(id))
        {
            return id;
        }

        id = Guid.NewGuid().ToString("N");
        httpContext.Response.Cookies.Append(CookieName, id, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(4)
        });
        return id;
    }
}

@using sv_19a9578ca5ea4e399ca3b78439ac7384.Services
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor

@{
    var steps = new[] { "Personal Info", "Experience", "References", "Review" };
}

@if (_data is not null)
{
    <div class="wizard-progress d-flex align-items-center gap-2 py-2">
        <strong>Step @_data.CurrentStep of @steps.Length</strong>
        @for (int i = 1; i <= steps.Length; i++)
        {
            var stepNum = i;
            var isCompleted = _data.CompletedSteps.Contains(stepNum);
            var isCurrent = _data.CurrentStep == stepNum;
            <span class="badge @(isCurrent ? "bg-primary" : isCompleted ? "bg-success" : "bg-secondary")">
                @stepNum. @steps[stepNum - 1]
            </span>
        }
    </div>
}

@code {
    private WizardData? _data;

    protected override void OnInitialized()
    {
        var ctx = HttpContextAccessor.HttpContext;
        if (ctx is null) return;

        var sessionId = WizardSessionHelper.GetOrCreateSessionId(ctx);
        _data = Store.GetOrCreate(sessionId);
    }
}

