@page "/apply/personal-info"
@rendermode InteractiveServer

@using sv_19a9578ca5ea4e399ca3b78439ac7384.Services
@inject WizardStateStore Store
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Step 1 – Personal Info</PageTitle>
<h3>Step 1: Personal Information</h3>

<EditForm Model="_data.PersonalInfo" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Name</label>
        <InputText class="form-control" @bind-Value="_data.PersonalInfo.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="_data.PersonalInfo.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private WizardData _data = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        var ctx = HttpContextAccessor.HttpContext;
        if (ctx is not null)
        {
            _sessionId = WizardSessionHelper.GetOrCreateSessionId(ctx);
            _data = Store.GetOrCreate(_sessionId);
            _data.CurrentStep = 1;
            _data.LastAccessed = DateTime.UtcNow;
        }
    }

    private void Next()
    {
        _data.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer

@using sv_19a9578ca5ea4e399ca3b78439ac7384.Services
@inject WizardStateStore Store
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Step 2 – Experience</PageTitle>
<h3>Step 2: Work Experience</h3>

<EditForm Model="_data" OnValidSubmit="Next" FormName="experience">
    @for (int i = 0; i < _data.Experience.Count; i++)
    {
        var entry = _data.Experience[i];
        <div class="card mb-3 p-3">
            <div class="mb-2">
                <label class="form-label">Company</label>
                <InputText class="form-control" @bind-Value="entry.Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Role</label>
                <InputText class="form-control" @bind-Value="entry.Role" />
            </div>
            <div class="mb-2">
                <label class="form-label">Years</label>
                <InputText class="form-control" @bind-Value="entry.Years" />
            </div>
        </div>
    }
    <button type="button" class="btn btn-outline-secondary me-2" @onclick="AddEntry">
        + Add another
    </button>
    <button type="button" class="btn btn-secondary me-2" @onclick="Back">← Back</button>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private WizardData _data = new();

    protected override void OnInitialized()
    {
        var ctx = HttpContextAccessor.HttpContext;
        if (ctx is not null)
        {
            var sessionId = WizardSessionHelper.GetOrCreateSessionId(ctx);
            _data = Store.GetOrCreate(sessionId);
            _data.CurrentStep = 2;
            _data.LastAccessed = DateTime.UtcNow;
        }
    }

    private void AddEntry() => _data.Experience.Add(new());
    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        _data.CompletedSteps.Add(2);
        Nav.NavigateTo("/apply/references");
    }
}

