toolArgs.file_text:
@page "/apply/review"
@rendermode InteractiveServer

@using sv_19a9578ca5ea4e399ca3b78439ac7384.Services
@inject WizardStateStore Store
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Step 4 – Review</PageTitle>
<h3>Step 4: Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <p><strong>Name:</strong> @_data.PersonalInfo.Name</p>
    <p><strong>Email:</strong> @_data.PersonalInfo.Email</p>
</div>

<div class="card mb-3 p-3">
    <h5>Work Experience</h5>
    @foreach (var exp in _data.Experience)
    {
        <p>@exp.Role at @exp.Company (@exp.Years years)</p>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @foreach (var r in _data.References)
    {
        <p>@r.Name – @r.Relationship – @r.Phone</p>
    }
</div>

<button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
<button class="btn btn-success" @onclick="Submit">Submit Application</button>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Application submitted!</div>
}

@code {
    private WizardData _data = new();
    private string _sessionId = "";
    private bool _submitted;

    protected override void OnInitialized()
    {
        var ctx = HttpContextAccessor.HttpContext;
        if (ctx is not null)
        {
            _sessionId = WizardSessionHelper.GetOrCreateSessionId(ctx);
            _data = Store.GetOrCreate(_sessionId);
            _data.CurrentStep = 4;
            _data.LastAccessed = DateTime.UtcNow;
        }
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        _data.CompletedSteps.Add(4);
        // TODO: persist to a database here
        Store.Remove(_sessionId);
        _submitted = true;
    }
}

